const fs = require("fs");
const path = require("path");

const rootDir = path.resolve(__dirname, "..");
const outputFile = path.join(rootDir, "dist", "bundle.js");

const sourceFiles = [
  "state.js",
  "calculations.js",
  "financeMetrics.js",
  "decisionMetrics.js",
  "analysisMetrics.js",
  "automationInsights.js",
  "experienceMetrics.js",
  "amortization.js",
  "storage.js",
  "ui/guideEngine.js",
  "engines/decisionEngine.js",
  "charts/chartConfigs.js",
  "charts/chartDataAdapter.js",
  "charts/chartService.js",
  "ui.js",
  "app.js",
];

const banner = [
  "/*",
  " * Auto-generated by scripts/build-bundle.js.",
  " * Edit source JS files, then run: node scripts/build-bundle.js",
  " */",
  "",
].join("\n");

const bundle = sourceFiles
  .map((relativePath) => {
    const absolutePath = path.join(rootDir, relativePath);
    const source = fs.readFileSync(absolutePath, "utf8").replace(/^\uFEFF/, "");
    return [
      `/* ===== ${relativePath} ===== */`,
      source.trimEnd(),
      "",
    ].join("\n");
  })
  .join("\n");

fs.writeFileSync(outputFile, `${banner}${bundle}`, "utf8");

console.log(`Built bundle.js from ${sourceFiles.length} files.`);
